package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.newFormat(',').withQuote('"').withAllowMissingColumnNames(false);
    }

    @Test
    public void testGetAllowMissingColumnNames() {
        // Given
        boolean expected = true;
        csvFormat = csvFormat.withAllowMissingColumnNames(expected);

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetAllowMissingColumnNames_Default() {
        // Given
        boolean expected = false;

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetAllowMissingColumnNames_Excel() {
        // Given
        boolean expected = true;
        csvFormat = CSVFormat.EXCEL.withAllowMissingColumnNames(expected);

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }
}
